// Build a professional assignment email
const { customer, broker, assignment } = $input.first().json;

const budgetStr = (customer.budget_min && customer.budget_max)
  ? `₹${customer.budget_min.toLocaleString('en-IN')} – ₹${customer.budget_max.toLocaleString('en-IN')} / month`
  : 'Not specified';

const regions = (customer.preferred_regions || []).join(', ') || 'Not specified';
const specials = (customer.special_requirements || []).length > 0
  ? customer.special_requirements.map(r => `  • ${r}`).join('\n')
  : '  None';

const emailSubject = `New Property Search Assignment — ${customer.name} (${customer.city})`;

const emailBody = `
Dear ${broker.name},

You have been assigned a new property search request through QuickMove.
Please review the customer requirements below and initiate property shortlisting.

──────────────────────────────────────────────
CUSTOMER DETAILS
──────────────────────────────────────────────
Name            : ${customer.name}
Destination     : ${customer.city}
Apartment Type  : ${customer.apartment_type || 'Not specified'}
Budget          : ${budgetStr}
Furnished       : ${customer.furnished_status || 'Not specified'}
Preferred Areas : ${regions}
Parking Needed  : ${customer.parking_required ? 'Yes' : 'No'}
Pets            : ${customer.pets_allowed ? 'Yes' : 'No'}
Office Location : ${customer.office_location || 'Not specified'}
Move Date       : ${customer.move_date || 'Flexible'}

Special Requirements:
${specials}

──────────────────────────────────────────────
ASSIGNMENT DETAILS
──────────────────────────────────────────────
Assignment ID   : #${assignment.id}
Assigned By     : ${assignment.approved_by}
Response By     : ${assignment.deadline || 'As soon as possible'}

──────────────────────────────────────────────

Next Steps:
1. Begin property search in the specified localities
2. Shortlist 3–5 properties matching the criteria
3. Share the shortlist with QuickMove within the deadline
4. Coordinate site visits with the customer

For questions, contact the QuickMove operations team.

Best regards,
QuickMove Operations
ops@quickmove.in | +91 80 4567 8900
`.trim();

return [{ json: { ...($input.first().json), emailSubject, emailBody } }];
